use strict;
use warnings;

my %plugins;

sub load_plugins {
    my $dir = 'config/plugins';

    opendir(my $dh, $dir) or die "Cannot open directory $dir: $!";

    while (my $file = readdir($dh)) {
        next unless -f "$dir/$file.pl"; # only load .pl files
        eval "use constant FILE => \"$file\";" and push @{ $plugins{$file} }, do "$dir/$file.pl";
